    private static final class AccountManager {
        private BigDecimal balance;

        AccountManager(BigDecimal initialBalance) {
            this.balance = initialBalance == null ? BigDecimal.ZERO.setScale(2, RoundingMode.HALF_UP)
                    : initialBalance.setScale(2, RoundingMode.HALF_UP);
        }

        synchronized BigDecimal getBalance() {
            return balance;
        }

        synchronized boolean deposit(BigDecimal amount) {
            if (!isValidAmount(amount)) return false;
            balance = balance.add(amount).setScale(2, RoundingMode.HALF_UP);
            return true;
        }

        synchronized boolean withdraw(BigDecimal amount) {
            if (!isValidAmount(amount)) return false;
            if (balance.compareTo(amount) < 0) return false;
            balance = balance.subtract(amount).setScale(2, RoundingMode.HALF_UP);
            return true;
        }

        private boolean isValidAmount(BigDecimal amount) {
            return amount != null && amount.compareTo(BigDecimal.ZERO) > 0;
        }
    }

    private enum TransactionType {
        DEPOSIT,
        WITHDRAWAL
    }

